mapper.select:
SELECT ri.id, ri.release_id, ri.issue_id, ri.task_id, ri.category, ri.notes,
       ri.added_by, ri.added_at,
       rp.name AS release_name, su.username AS added_by_name
FROM release_issue ri
LEFT JOIN release_plan rp ON ri.release_id = rp.id AND rp.deleted = 0
LEFT JOIN sys_user su ON ri.added_by = su.id AND su.deleted = 0
WHERE ri.deleted = 0
AND ri.release_id = #{releaseId}
AND ri.issue_id = #{issueId}
AND ri.task_id = #{taskId}
AND ri.category = #{category}
ORDER BY ri.added_at DESC
